export type TAudioLoopMode = `${AUDIO_LOOP_MODE}`

// Where AUDIO_LOOP_MODE is:
export enum AUDIO_LOOP_MODE {
    NONE = 'none',
    ALL  = 'all',
    ONE  = 'one'
}

export type TAudioVariant = `${AUDIO_VARIANT}`

// Where AUDIO_VARIANT is:
export enum AUDIO_VARIANT {
    EXPANDED = 'expanded',
    COMPACT  = 'compact',
    /** @deprecated Use EXPANDED */ NORMAL  = 'normal',
    /** @deprecated Use COMPACT  */ MINIMAL = 'minimal'
}

export type TBottomNavPosition = `${BOTTOM_NAV_POSITION}`

// Where BOTTOM_NAV_POSITION is:
export enum BOTTOM_NAV_POSITION {
    START  = 'start',
    CENTER = 'center',
    END    = 'end'
}

export type TBracketVariant = `${BRACKET_VARIANT}`

// Where BRACKET_VARIANT is:
export enum BRACKET_VARIANT {
    SINGLE_ELIMINATION = 'single-elimination',
    DOUBLE_ELIMINATION = 'double-elimination',
    ROUND_ROBIN        = 'round-robin'
}

export type TBreadcrumbItem = string | Partial<IBreadcrumbItemProps>

// Where IBreadcrumbItemProps contains:
// title: string          — display label (required when using object form)
// disabled?: boolean     — greys out and disables the link
// href?: string          — navigates to an external URL
// to?: RouteLocationRaw  — navigates via vue-router
// (+ all Commons props: color, bgColor, border, padding, margin, rounded, density…)

export type TCardType = `${CARD_TYPE}`

// Where CARD_TYPE is:
export enum CARD_TYPE {
    GRID = 'grid',
    LIST = 'list'
}

export type TChartStacking = `${CHART_STACKING}`

// Where CHART_STACKING is:
export enum CHART_STACKING {
    NORMAL  = 'normal',
    PERCENT = 'percent'
}

export type TChartHoneycombColorMode = `${CHART_HONEYCOMB_COLOR_MODE}`

// Where CHART_HONEYCOMB_COLOR_MODE is:
export enum CHART_HONEYCOMB_COLOR_MODE {
    CATEGORICAL = 'categorical',
    HEATMAP     = 'heatmap'
}

export type TCoverPosition = `${COVER_POSITION}`

// Where COVER_POSITION is:
export enum COVER_POSITION {
    LEFT  = 'left',
    RIGHT = 'right'
}

export type TCrossOrigin = `${CROSS_ORIGIN}` | ''

// Where CROSS_ORIGIN is:
export enum CROSS_ORIGIN {
    ANONYMOUS        = 'anonymous',
    USE_CREDENTIALS  = 'use-credentials'
}

export type TDateMode = `${DATE_MODE}`

// Where DATE_MODE is:
export enum DATE_MODE {
    MONTH  = 'month',
    MONTHS = 'months',
    YEARS  = 'years'
}

export type TDensity = `${DENSITY}`

// Where DENSITY is:
export enum DENSITY {
    DEFAULT     = 'default',
    COMPACT     = 'compact',
    COMFORTABLE = 'comfortable',
}

export type TDirection = `${DIRECTION}`

// Where DIRECTION is:
export enum DIRECTION {
    HORIZONTAL = 'horizontal',
    VERTICAL   = 'vertical'
}

// number: raw pixel threshold
// TBreakpoint: one of the named breakpoints from the BREAKPOINTS enum
type TDisplayLevel = number | TBreakpoint

// Where TBreakpoint is:
export type TBreakpoint = `${BREAKPOINTS}`

export enum BREAKPOINTS {
    XS  = 'xs',
    SM  = 'sm',
    MD  = 'md',
    LG  = 'lg',
    XL  = 'xl',
    XXL = 'xxl',
}

export type TFlexDirection = `${FLEX_DIRECTION}`

// Where FLEX_DIRECTION is:
export enum FLEX_DIRECTION {
    ROW            = 'row',
    COLUMN         = 'column',
    COLUMN_REVERSE = 'column-reverse',
    ROW_REVERSE    = 'row-reverse',
}

