export type TInfiniteScrollSide = `${INFINITE_SCROLL_SIDE}`

// Where INFINITE_SCROLL_SIDE is:
export enum INFINITE_SCROLL_SIDE {
    START = 'start',
    END   = 'end',
    BOTH  = 'both'
}

export type TLines = `${LINES}`

// Where LINES is:
export enum LINES {
    ONE   = 'one',
    TWO   = 'two',
    THREE = 'three'
}

export type TLoadingValue = boolean | number | TLoaderConfig

// Where TLoaderConfig is:
export type TLoaderConfig =
    | ({ type: 'line' }     & Partial<IProgressLinearProps>)
    | ({ type: 'circular' } & Partial<IProgressCircularProps>)
    | ({ type: 'skeleton' } & Partial<ISkeletonProps>)

export type TLocationStrategy = `${LOCATION_STRATEGIES}`

// Where LOCATION_STRATEGIES is:
export enum LOCATION_STRATEGIES {
    STATIC    = 'static',
    CONNECTED = 'connected'
}

export type TMasonryAlign =
    | 'top'
    | 'center'

export type TMode = `${MODE}`

// Where MODE is:
export enum MODE {
    HORIZONTAL = 'horizontal',
    VERTICAL   = 'vertical',
    SHIFT      = 'shift'
}

export type TPosition = `${POSITION}`

// Where POSITION is:
export enum POSITION {
    STATIC   = 'static',
    RELATIVE = 'relative',
    FIXED    = 'fixed',
    ABSOLUTE = 'absolute',
    STICKY   = 'sticky'
}

// From vue-router
export type RouteLocationRaw =
    | string
    | RouteLocationPathRaw
    | RouteLocationNameRaw

export type TScrollStrategy = `${SCROLL_STRATEGIES}`

// Where SCROLL_STRATEGIES is:
export enum SCROLL_STRATEGIES {
    NONE        = 'none',
    CLOSE       = 'close',
    BLOCK       = 'block',
    REPOSITION  = 'reposition'
}

export type TSize = `${SIZES}`

// Where SIZES is:
export enum SIZES {
    X_SMALL = 'x-small',
    SMALL   = 'small',
    DEFAULT = 'default',
    LARGE   = 'large',
    X_LARGE = 'x-large'
}

export type TSliderFieldVariant = `${SLIDER_FIELD_VARIANT}`

// Where SLIDER_FIELD_VARIANT is:
export enum SLIDER_FIELD_VARIANT {
    FIELD = 'field',
    TIMER = 'timer',
    AUDIO = 'audio'
}

export type TStatus = `${STATUS}`

// Where STATUS is:
export enum STATUS {
    SUCCESS = 'success',
    INFO    = 'info',
    WARNING = 'warning',
    ERROR   = 'error'
}

export type TTextareaMode = `${TEXTAREA_MODE}`

// Where TEXTAREA_MODE is:
export enum TEXTAREA_MODE {
    PLAIN = 'plain',
    RICH  = 'rich'
}

export type TTextareaOutput = `${TEXTAREA_OUTPUT}`

// Where TEXTAREA_OUTPUT is:
export enum TEXTAREA_OUTPUT {
    HTML     = 'html',
    MARKDOWN = 'markdown'
}

export type TTextareaToolbarPosition = `${TEXTAREA_TOOLBAR_POSITION}`

// Where TEXTAREA_TOOLBAR_POSITION is:
export enum TEXTAREA_TOOLBAR_POSITION {
    TOP      = 'top',
    BOTTOM   = 'bottom',
    FLOATING = 'floating'
}

export type TTransitionMode = `${TRANSITION_MODE}`

// Where TRANSITION_MODE is:
export enum TRANSITION_MODE {
    IN_OUT  = 'in-out',
    OUT_IN  = 'out-in',
    DEFAULT = 'default'
}

export type TTransitionMode = `${TRANSITION_MODE}`

// Where TRANSITION_MODE is:
export enum TRANSITION_MODE {
    IN_OUT  = 'in-out',
    OUT_IN  = 'out-in',
    DEFAULT = 'default'
}
